function StructPetDreamLandInfo:CreateByPb(pb)
	self.landDataMap = {}

	local landData = pb.landData or {}
	for i,v in ipairs(landData) do
		---@type StructPetDreamLandData
		local data = StructPetDreamLandData:New()
		data:CreateByPb(v)
		self.landDataMap[data.refId] = data
	end

	self:UpdatePlayerOccupyMap()

	self:UpdatePlayerOccupyNum()

	self:SetFreeTime(pb.freeTime)

	self:SetTotalFreeTime(pb.totalFreeTime)

	self:SetPayTime(pb.payTime)

	self:SetTotalTime(pb.totalTime)

	self.lottery = {}
	local lottery = pb.lottery or {}
	for i,v in ipairs(lottery) do
		self:UpdateInfoLotteryData(v)
	end

	self.state = pb.state

	self.startTime = tonumber(pb.startTime)

	self.endTime = tonumber(pb.endTime)

	self.bigFightId = pb.bigFightId

	self.smallFightNum = pb.smallFightNum

	self.dailySteals = {}
	self:UpdateDailySteals(pb.dailySteals)
end

--- 更新玩家占领节点数据
function StructPetDreamLandInfo:UpdatePlayerOccupyMap()
	self.playerOccupyMap = {}
	for refId,landData in pairs(self.landDataMap) do
		if landData:CheckIsPlayerOccupy() then
			---@type table<string,StructPetDreamLandPointData>
			local map = {}
			local list = landData:GetPlayerPointDatas()
			---@param val StructPetDreamLandPointData
			for idx,val in ipairs(list) do
				map[val.id] = val
			end
			self.playerOccupyMap[landData.refId] = map
		end
	end
end

--- 更新玩家占领节点数
function StructPetDreamLandInfo:UpdatePlayerOccupyNum()
	local num = 0
	for k,v in pairs(self.playerOccupyMap) do
		for key,data in pairs(v) do
			num = num + 1
		end
	end
	self.playerOccupyNum = num
end

--- 是否开启
function StructPetDreamLandInfo:DreamLandIsOpen()
	return self.state == 1
end

