---@param pointData StructPetDreamLandPointData 据点信息
function StructPetDreamLandInfo:UpdatePetDreamLandPointData(refId,pointData)
	if not refId then return end

	if not pointData then return end

	---@type StructPetDreamLandData
	local landData = self:GetPetDreamLandDataByRefId(refId)
	if not landData then
		---@type StructPetDreamLandData
		landData = StructPetDreamLandData:New()
		landData:SetRefId(refId)
		self.landDataMap[refId] = landData
	end

	local pointPlayerId = pointData.playerId
	local myPlayerId = gModelPlayer:GetPlayerId()
	if myPlayerId == pointPlayerId then
		local playerOccupys = self.playerOccupyMap[refId]
		if not playerOccupys then
			playerOccupys = {}
			self.playerOccupyMap[refId] = playerOccupys
		end
		playerOccupys[pointData.id] = pointData
		self:UpdatePlayerOccupyNum()
	end

	landData:UpdatePetDreamLandPointData(pointData)
end

