--- 删除 据点数据
function StructPetDreamLandInfo:DelectPetDreamLandPointData(refId,pointId)
	if not refId then return end

	if not pointId then return end

	---@type StructPetDreamLandData
	local landData = self:GetPetDreamLandDataByRefId(refId)
	if not landData then return end

	local playerOccupys = self.playerOccupyMap[refId]
	if playerOccupys and playerOccupys[pointId] then
		self.playerOccupyMap[refId][pointId] = nil
	end

	self:UpdatePlayerOccupyNum()
	landData:DelectPetDreamLandPointData(pointId)
end

