---@param refId number 当前据点refId是否有占领
function StructPetDreamLandInfo:CheckPointRefIdIsOccupy(refId)
	---@type table<string,StructPetDreamLandPointData>
	local playerOccupys = self.playerOccupyMap[refId]
	if not playerOccupys then return false end
	local num = 0
	for k,v in pairs(playerOccupys) do
		num = num + 1
	end
	return num > 0
end

function StructPetDreamLandInfo:GetPlayerOccupyList()
	local list = {}

	---@param v table<string,StructPetDreamLandPointData>
	for k,v in pairs(self.playerOccupyMap) do
		---@param val StructPetDreamLandPointData
		for idx,val in pairs(v) do
			table.insert(list,{
				pointData = val,
				refId = k,
			})
		end
	end
	table.sort(list,function(a, b)
		---@type StructPetDreamLandPointData
		local pointDataA = a.pointData

		---@type StructPetDreamLandPointData
		local pointDataB = b.pointData

		return pointDataA.starOccupyTime < pointDataB.starOccupyTime
	end)

	return list
end

---@return table 获取占领时间最长
function StructPetDreamLandInfo:GetPlayerOccupyLongestTimeData()
	local list = self:GetPlayerOccupyList()
	if #list < 1 then return end
	return list[1]
end

---@return StructPetDreamLandPointData 通过 refId 返回 StructPetDreamLandPointData 结构数据
function StructPetDreamLandInfo:GetPointDatasByRefId(refId)
	---@type table<string,StructPetDreamLandPointData>
	local playerOccupys = self.playerOccupyMap[refId]
	if not playerOccupys then return end

	---@type table<StructPetDreamLandPointData>
	local list = {}
	for k,v in pairs(playerOccupys) do
		table.insert(list,v)
	end
	if #list < 1 then return end

	table.sort(list,function(a,b)
		return a.starOccupyTime < b.starOccupyTime
	end)
	return list[1]
end

function StructPetDreamLandInfo:UpdateDailySteals(pb_dailySteals)
	local dailySteals = self.dailySteals
	if not dailySteals then
		dailySteals = {}
		self.dailySteals = dailySteals
	end
	pb_dailySteals = pb_dailySteals or {}
	for i,v in ipairs(pb_dailySteals) do
		dailySteals[v] = true
	end
	self.dailySteals = dailySteals
end

---@return boolean 是否可偷袭
function StructPetDreamLandInfo:CheckIsCanSteal(playerId)
	local dailySteals = self.dailySteals
	if dailySteals[playerId] then
		return false
	end
	return true
end

